import scala.collection.mutable

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val directions = Array((0, 1), (1, 0)) // right and down
  val heap = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](
    Ordering.by(-_._1) // min-heap based on cost
  )
  heap.enqueue((0L, 0, 0, k.toInt))
  val visited = mutable.Map[(Int, Int, Int), Long]().withDefaultValue(Long.MaxValue)

  while (heap.nonEmpty) {
    val (cost, i, j, remainingK) = heap.dequeue()
    if (i == m - 1 && j == n - 1) {
      return cost
    }
    if (visited((i, j, remainingK)) <= cost) {
      continue
    }
    visited((i, j, remainingK)) = cost

    // Normal moves
    for ((di, dj) <- directions) {
      val ni = i + di
      val nj = j + dj
      if (ni < m && nj < n) {
        val newCost = cost + grid(ni)(nj)
        if (newCost < visited((ni, nj, remainingK))) {
          heap.enqueue((newCost, ni, nj, remainingK))
        }
      }
    }

    // Teleport moves
    if (remainingK > 0) {
      for {
        x <- 0 until m
        y <- 0 until n
        if grid(x)(y) <= grid(i)(j) && (x != i || y != j)
      } {
        val newCost = cost
        if (newCost < visited((x, y, remainingK - 1))) {
          heap.enqueue((newCost, x, y, remainingK - 1))
        }
      }
    }
  }
  -1L // should not reach here if path exists
}
