import scala.collection.mutable.PriorityQueue

class SegmentTree(size: Int, init: Long = Long.MaxValue) {
  private val n: Int = size
  private val tree: Array[Long] = Array.fill(2 * n)(init)

  def update(index: Int, value: Long): Unit = {
    var idx = index + n
    tree(idx) = Math.min(tree(idx), value)
    idx = idx / 2
    while (idx > 0) {
      tree(idx) = Math.min(tree(2 * idx), tree(2 * idx + 1))
      idx /= 2
    }
  }

  def query(left: Int, right: Int): Long = {
    var l = left + n
    var r = right + n
    var minVal = Long.MaxValue
    while (l <= r) {
      if (l % 2 == 1) {
        minVal = Math.min(minVal, tree(l))
        l += 1
      }
      if (r % 2 == 0) {
        minVal = Math.min(minVal, tree(r))
        r -= 1
      }
      l /= 2
      r /= 2
    }
    minVal
  }
}

object Solution {
  def solve(grid: Array[Array[Long]], k: Int): Long = {
    val m = grid.length
    val n = grid(0).length
    val INF = Long.MaxValue / 2
    val maxValue = 10000
    val pq = PriorityQueue.empty[(Long, Int, Int, Int)](Ordering.by(-_._1))
    val dp = Array.fill(k + 1, m, n)(INF)
    val trees = Array.fill(k + 1)(new SegmentTree(maxValue + 1, INF))

    dp(0)(0)(0) = 0
    pq.enqueue((0L, 0, 0, 0))

    while (pq.nonEmpty) {
      val (cost, t, i, j) = pq.dequeue()
      if (cost == dp(t)(i)(j)) {
        trees(t).update(grid(i)(j).toInt, cost)
        if (i == m - 1 && j == n - 1) return cost
        if (t < k) {
          val targetCost = trees(t).query(0, grid(i)(j).toInt)
          if (targetCost != INF) {
            for {
              x <- 0 until m
              y <- 0 until n
            } {
              if (grid(x)(y) <= grid(i)(j)) {
                val newCost = targetCost
                if (newCost < dp(t + 1)(x)(y)) {
                  dp(t + 1)(x)(y) = newCost
                  pq.enqueue((newCost, t + 1, x, y))
                }
              }
            }
          }
        }
        val moves = List((0, 1), (1, 0))
        for {
          (dx, dy) <- moves
          ni = i + dx
          nj = j + dy
          if ni < m && nj < n
        } {
          val newCost = cost + grid(ni)(nj)
          if (newCost < dp(t)(ni)(nj)) {
            dp(t)(ni)(nj) = newCost
            pq.enqueue((newCost, t, ni, nj))
          }
        }
      }
    }
    dp(k)(m - 1)(n - 1)
  }
}
